import { createClient, SupabaseClient } from "@supabase/supabase-js";

export function getSupabasePublic(): SupabaseClient | null {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  if (!url || !key) return null;
  return createClient(url, key);
}

import { blogPostsStatic } from "@/content/site";
import { getSupabasePublic } from "@/lib/supabase/public-client";

export type BlogPost = {
  slug: string;
  title: string;
  excerpt: string;
  image: string;
  date: string;
};

export async function getBlogPosts(): Promise<BlogPost[]> {
  const supabase = getSupabasePublic();
  if (!supabase) {
    return blogPostsStatic;
  }

  const { data, error } = await supabase
    .from("posts")
    .select("slug, title, excerpt, cover_image, published_at")
    .not("published_at", "is", null)
    .order("published_at", { ascending: false })
    .limit(6);

  if (error || !data?.length) {
    return blogPostsStatic;
  }

  return data.map((row) => ({
    slug: row.slug,
    title: row.title,
    excerpt: row.excerpt ?? "",
    image: row.cover_image ?? blogPostsStatic[0].image,
    date: row.published_at?.slice(0, 10) ?? "",
  }));
}

"use server";

import { getSupabasePublic } from "@/lib/supabase/public-client";

export type ContactState = { ok: boolean; message: string };

export async function submitContact(
  _prevState: ContactState,
  formData: FormData,
): Promise<ContactState> {
  const name = String(formData.get("name") ?? "").trim();
  const email = String(formData.get("email") ?? "").trim();
  const phone = String(formData.get("phone") ?? "").trim();
  const message = String(formData.get("message") ?? "").trim();

  if (!name || !email || !message) {
    return { ok: false, message: "Please fill name, email, and message." };
  }

  const supabase = getSupabasePublic();
  if (supabase) {
    const { error } = await supabase.from("contact_inquiries").insert({
      name,
      email,
      phone: phone || null,
      message,
    });
    if (error) {
      return {
        ok: false,
        message: "Could not send right now. Please call or email us directly.",
      };
    }
  }

  return {
    ok: true,
    message: supabase
      ? "Thank you — we will get back to you shortly."
      : "Thank you — your message was received. (Connect Supabase to store inquiries.)",
  };
}

